import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { FaDollarSign, FaCar, FaUsers, FaCalendarAlt } from 'react-icons/fa';

const SuperAdminDashboard = () => {
  const [stats, setStats] = useState({
    totalRevenue: 0,
    totalBookings: 0,
    totalCars: 0,
    totalUsers: 0
  });

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const [bookings, cars, users] = await Promise.all([
        axios.get('http://localhost:5000/api/bookings'),
        axios.get('http://localhost:5000/api/cars'),
        axios.get('http://localhost:5000/api/users')
      ]);

      const revenue = bookings.data.data.reduce((sum, b) => sum + b.totalPrice, 0);

      setStats({
        totalRevenue: revenue,
        totalBookings: bookings.data.data.length,
        totalCars: cars.data.count,
        totalUsers: users.data.data.length
      });
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  return (
    <div>
      <h1>Super Admin Dashboard</h1>
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon blue">
            <FaDollarSign />
          </div>
          <div className="stat-info">
            <h3>Total Revenue</h3>
            <p>${stats.totalRevenue.toLocaleString()}</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon green">
            <FaCalendarAlt />
          </div>
          <div className="stat-info">
            <h3>Total Bookings</h3>
            <p>{stats.totalBookings}</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon orange">
            <FaCar />
          </div>
          <div className="stat-info">
            <h3>Total Cars</h3>
            <p>{stats.totalCars}</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon red">
            <FaUsers />
          </div>
          <div className="stat-info">
            <h3>Total Users</h3>
            <p>{stats.totalUsers}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SuperAdminDashboard;
